    10→export function generateStaticParams() {
    11→  if (siteConfig.features?.flow?.enabled === false) return [{ year: '_' }];
    12→  const allFlows = getAllFlows();
    13→  if (allFlows.length === 0) return [{ year: '_' }];
    14→  const years = new Set(allFlows.map(f => f.slug.split('/')[0]));
    15→  return Array.from(years).map(year => ({ year }));
    16→}
    17→
    18→export const dynamicParams = false;
    19→
    20→export async function generateMetadata({ params }: { params: Promise<{ year: string }> }): Promise<Metadata> {
    21→  const { year } = await params;
    22→  return {
    23→    title: `${tWith('flows_in_year', { year })} | ${resolveLocale(siteConfig.title)}`,
    24→  };
    25→}
    26→
    27→export default async function FlowsYearPage({ params }: { params: Promise<{ year: string }> }) {
    28→  if (siteConfig.features?.flow?.enabled === false) notFound();
    29→  const { year } = await params;
    30→  const flows = getFlowsByYear(year);
    31→  if (flows.length === 0) notFound();
    32→
    33→  const allFlows = getAllFlows();
    34→  const entryDates = allFlows.map(f => f.date);
    35→  const tags = getFlowTags();
    36→
    37→  // Build month counts for this year
    38→  const monthCounts: Record<string, number> = {};
    39→  for (const flow of flows) {
    40→    const month = flow.date.split('-')[1];
    41→    monthCounts[month] = (monthCounts[month] || 0) + 1;
    42→  }
    43→  const sortedMonths = Object.keys(monthCounts).sort();
    44→
    45→  const monthNames = [
    46→    'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
    47→    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
    48→  ];
    49→
    50→  const breadcrumb = (
    51→    <div className="space-y-2">
    52→      <nav aria-label="Breadcrumb" className="flex items-center gap-1.5 text-sm text-muted">
    53→        <Link href="/flows" className="hover:text-accent no-underline">
    54→          {t('all_flows')}
    55→        </Link>
    56→        <span className="text-muted/40" aria-hidden="true">›</span>
    57→        <span className="text-foreground">{year}</span>
    58→      </nav>
    59→      <div className="flex flex-wrap gap-1.5">
    60→        {sortedMonths.map(m => (
    61→          <Link
    62→            key={m}
    63→            href={`/flows/${year}/${m}`}
    64→            className="inline-flex items-center gap-1 px-2.5 py-0.5 text-xs rounded-full border border-muted/20 text-foreground hover:border-accent hover:text-accent no-underline transition-colors"
    65→          >
    66→            {monthNames[parseInt(m, 10) - 1]}
    67→            <span className="text-muted text-[10px]">({monthCounts[m]})</span>
    68→          </Link>
    69→        ))}
    70→      </div>
    71→    </div>
    72→  );
    73→
    74→  return (
    75→    <div className="layout-main">
    76→      <PageHeader
    77→        titleKey="flows_in_year"
    78→        titleParams={{ year }}
    79→        subtitleKey="flow_subtitle"
    80→        subtitleParams={{ count: flows.length }}
    81→      />
    82→
    83→      <FlowContent
    84→        flows={flows}
    85→        entryDates={entryDates}
    86→        tags={tags}
    87→        currentDate={`${year}-01-01`}
    88→        breadcrumb={breadcrumb}
    89→      />
    90→    </div>
    91→  );
    92→}
