    94→
    95→          <Backlinks backlinks={backlinks} />
    96→
    97→          <ShareBar url={flowUrl} title={flow.title} className="mt-8 mb-2" />
    98→
    99→          {/* Prev/Next navigation */}
   100→          <nav aria-label="Post navigation" className="mt-12 pt-12 border-t border-muted/20 grid grid-cols-2 gap-4">
