     3→import { useState, useMemo, type ReactNode } from 'react';
     4→import { useLanguage } from '@/components/LanguageProvider';
     5→import FlowCalendarSidebar from '@/components/FlowCalendarSidebar';
     6→import FlowTimelineEntry from '@/components/FlowTimelineEntry';
     7→import Pagination from '@/components/Pagination';
     8→
     9→interface FlowItem {
    10→  slug: string;
    11→  date: string;
    12→  title: string;
    13→  excerpt: string;
    14→  tags: string[];
    15→}
    16→
    17→interface FlowContentProps {
    18→  flows: FlowItem[];
    19→  entryDates: string[];
    20→  tags: Record<string, number>;
    21→  currentDate?: string;
    22→  pagination?: {
    23→    currentPage: number;
    24→    totalPages: number;
    25→    basePath: string;
    26→  };
    27→  breadcrumb?: ReactNode;
    28→}
    29→
    30→export default function FlowContent({ flows, entryDates, tags, currentDate, pagination, breadcrumb }: FlowContentProps) {
    31→  const { t } = useLanguage();
    32→  const [selectedTag, setSelectedTag] = useState<string | null>(null);
    33→
    34→  const filteredFlows = useMemo(() => {
    35→    if (!selectedTag) return flows;
    36→    return flows.filter(f => f.tags.includes(selectedTag));
    37→  }, [flows, selectedTag]);
    38→
    39→  function handleTagSelect(tag: string) {
    40→    setSelectedTag(prev => (prev === tag ? null : tag));
    41→  }
    42→
    43→  return (
    44→    <div className="flex gap-10">
    45→      <FlowCalendarSidebar
    46→        entryDates={entryDates}
    47→        currentDate={currentDate}
    48→        tags={tags}
    49→        selectedTag={selectedTag}
    50→        onTagSelect={handleTagSelect}
    51→        breadcrumb={breadcrumb}
    52→      />
    53→
    54→      <div className="flex-1 min-w-0">
    55→        {selectedTag && (
    56→          <div className="flex items-center gap-2 mb-4 text-sm text-muted">
    57→            <span>
    58→              {filteredFlows.length} / {flows.length}
    59→            </span>
    60→            <button
    61→              onClick={() => setSelectedTag(null)}
    62→              className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full border border-muted/20 text-xs hover:border-accent hover:text-accent transition-colors"
    63→            >
    64→              ✕ {t('clear')}
    65→            </button>
    66→          </div>
    67→        )}
    68→
    69→        {filteredFlows.length === 0 ? (
    70→          <p className="text-muted">{t('no_flows')}</p>
    71→        ) : (
    72→          <div className="space-y-0">
    73→            {filteredFlows.map(flow => (
    74→              <FlowTimelineEntry
    75→                key={flow.slug}
    76→                date={flow.date}
    77→                excerpt={flow.excerpt}
    78→                tags={flow.tags}
    79→                slug={flow.slug}
    80→              />
    81→            ))}
    82→          </div>
    83→        )}
    84→
    85→        {pagination && pagination.totalPages > 1 && (
    86→          <div className="mt-12">
    87→            <Pagination
    88→              currentPage={pagination.currentPage}
    89→              totalPages={pagination.totalPages}
    90→              basePath={pagination.basePath}
    91→            />
    92→          </div>
    93→        )}
    94→      </div>
    95→    </div>
    96→  );
    97→}
    98→

