   885→function flattenBookChapters(toc: BookTocItem[]): BookChapterEntry[] {
   886→  const result: BookChapterEntry[] = [];
   887→  for (const item of toc) {
   888→    if ('part' in item) {
   889→      for (const ch of item.chapters) {
   890→        result.push({ title: ch.title, id: ch.id, part: item.part });
   891→      }
   892→    } else {
   893→      result.push({ title: item.title, id: item.id });
