   899→export function getBookData(slug: string): BookData | null {
   900→  if (!fs.existsSync(booksDirectory)) return null;
   901→  const bookDir = path.join(booksDirectory, slug);
   902→  if (!fs.existsSync(bookDir)) return null;
   903→
   904→  const indexPathMdx = path.join(bookDir, 'index.mdx');
   905→  const indexPathMd = path.join(bookDir, 'index.md');
   906→  let fullPath = '';
   907→  if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   908→  else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   909→  else return null;
   910→
   911→  const fileContents = fs.readFileSync(fullPath, 'utf8');
   912→  const { data: rawData, content } = matter(fileContents);
   913→
   914→  const parsed = BookSchema.safeParse(rawData);
   915→  if (!parsed.success) {
   916→    console.error(`Invalid book frontmatter in ${fullPath}:`, parsed.error.format());
   917→    return null;
   918→  }
   919→  const data = parsed.data;
   920→
   921→  // Warn about missing chapter files
   922→  const chapters = flattenBookChapters(data.chapters);
   923→  for (const ch of chapters) {
   924→    const chMdx = path.join(bookDir, `${ch.id}.mdx`);
   925→    const chMd = path.join(bookDir, `${ch.id}.md`);
   926→    const chFolderMdx = path.join(bookDir, ch.id, 'index.mdx');
   927→    const chFolderMd = path.join(bookDir, ch.id, 'index.md');
   928→    if (!fs.existsSync(chMdx) && !fs.existsSync(chMd) && !fs.existsSync(chFolderMdx) && !fs.existsSync(chFolderMd)) {
   929→      console.warn(`Book "${slug}": chapter "${ch.id}" not found`);
   930→    }
   931→  }
   932→
   933→  let coverImage = data.coverImage;
   934→  if (coverImage && !coverImage.startsWith('http') && !coverImage.startsWith('/') && !coverImage.startsWith('text:')) {
   935→    const cleanPath = coverImage.replace(/^\.\//, '');
   936→    coverImage = `/books/${slug}/${cleanPath}`;
   937→  }
   938→
   939→  let authors = data.authors;
   940→  if (authors.length === 0) {
   941→    authors = ['Amytis'];
   942→  }
   943→
   944→  return {
   945→    title: data.title,
   946→    slug,
   947→    excerpt: data.excerpt,
   948→    date: data.date,
   949→    coverImage,
   950→    featured: data.featured,
   951→    draft: data.draft,
   952→    authors,
   953→    content: content.trim(),
   954→    toc: data.chapters,
   955→    chapters,
   956→  };
   957→}
   958→
   959→export function getBookChapter(bookSlug: string, chapterSlug: string): BookChapterData | null {
   960→  const book = getBookData(bookSlug);
   961→  if (!book) return null;
   962→
   963→  const bookDir = path.join(booksDirectory, bookSlug);
   964→  const chMdx = path.join(bookDir, `${chapterSlug}.mdx`);
   965→  const chMd = path.join(bookDir, `${chapterSlug}.md`);
   966→  const chFolderMdx = path.join(bookDir, chapterSlug, 'index.mdx');
   967→  const chFolderMd = path.join(bookDir, chapterSlug, 'index.md');
   968→  let fullPath = '';
   969→  let isFolder = false;
   970→  if (fs.existsSync(chMdx)) fullPath = chMdx;
   971→  else if (fs.existsSync(chMd)) fullPath = chMd;
   972→  else if (fs.existsSync(chFolderMdx)) { fullPath = chFolderMdx; isFolder = true; }
   973→  else if (fs.existsSync(chFolderMd)) { fullPath = chFolderMd; isFolder = true; }
   974→  else return null;
   975→
   976→  const fileContents = fs.readFileSync(fullPath, 'utf8');
   977→  const { data: rawData, content } = matter(fileContents);
   978→
   979→  const parsed = BookChapterSchema.safeParse(rawData);
   980→  if (!parsed.success) {
   981→    console.error(`Invalid chapter frontmatter in ${fullPath}:`, parsed.error.format());
   982→    return null;
   983→  }
   984→  const data = parsed.data;
   985→
   986→  if (process.env.NODE_ENV === 'production' && data.draft) {
   987→    return null;
   988→  }
   989→
   990→  const contentWithoutH1 = content.replace(/^\s*#\s+[^\n]+/, '').trim();
   991→  const headings = getHeadings(content);
   992→  const readingTime = calculateReadingTime(contentWithoutH1);
   993→  const excerpt = data.excerpt || generateExcerpt(contentWithoutH1);
   994→
   995→  // Find prev/next
   996→  const chapterIndex = book.chapters.findIndex(ch => ch.id === chapterSlug);
   997→  const prevChapter = chapterIndex > 0 ? book.chapters[chapterIndex - 1] : null;
   998→  const nextChapter = chapterIndex < book.chapters.length - 1 ? book.chapters[chapterIndex + 1] : null;
   999→
  1000→  return {
  1001→    title: data.title,
  1002→    slug: chapterSlug,
  1003→    bookSlug,
  1004→    content: contentWithoutH1,
  1005→    headings,
  1006→    excerpt,
  1007→    latex: data.latex,
  1008→    readingTime,
  1009→    isFolder,
  1010→    prevChapter: prevChapter ? { title: prevChapter.title, id: prevChapter.id } : null,
  1011→    nextChapter: nextChapter ? { title: nextChapter.title, id: nextChapter.id } : null,
  1012→  };
  1013→}
  1014→
  1015→export function getAllBooks(): BookData[] {
  1016→  if (!fs.existsSync(booksDirectory)) return [];
  1017→
  1018→  const entries = fs.readdirSync(booksDirectory, { withFileTypes: true });
  1019→  const books: BookData[] = [];
  1020→
  1021→  for (const entry of entries) {
  1022→    if (!entry.isDirectory()) continue;
  1023→    const book = getBookData(entry.name);
  1024→    if (!book) continue;
  1025→    if (process.env.NODE_ENV === 'production' && book.draft) continue;
  1026→    books.push(book);
  1027→  }
  1028→
  1029→  return books.sort((a, b) => (a.date < b.date ? 1 : -1));
  1030→}
  1031→
  1032→export function getFeaturedBooks(): BookData[] {
  1033→  return getAllBooks().filter(book => book.featured);
  1034→}
  1035→
  1036→export function getBooksByAuthor(author: string): BookData[] {
