  1061→
  1062→function parseFlowFile(fullPath: string, slug: string): FlowData {
  1063→  const fileContents = fs.readFileSync(fullPath, 'utf8');
  1064→  const { data: rawData, content } = matter(fileContents);
  1065→
  1066→  const parsed = FlowSchema.safeParse(rawData);
  1067→  if (!parsed.success) {
  1068→    console.error(`Invalid flow frontmatter in ${fullPath}:`, parsed.error.format());
  1069→    throw new Error(`Invalid flow frontmatter in ${fullPath}`);
  1070→  }
  1071→  const data = parsed.data;
  1072→
  1073→  const contentWithoutH1 = content.replace(/^\s*#\s+[^\n]+/, '').trim();
  1074→  const date = data.date || slug.replace(/\//g, '-'); // slug is YYYY/MM/DD, convert to YYYY-MM-DD
  1075→  const excerpt = generateExcerpt(contentWithoutH1);
  1076→  const headings = getHeadings(content);
  1077→
  1078→  return {
  1079→    slug,
  1080→    date,
  1081→    title: data.title ?? date, // fall back to date string if no title in frontmatter
  1082→    tags: data.tags,
  1083→    draft: data.draft,
  1084→    content: contentWithoutH1,
  1085→    excerpt,
  1086→    headings,
  1087→  };
