  1090→export function getAllFlows(): FlowData[] {
  1091→  if (!fs.existsSync(flowsDirectory)) return [];
  1092→
  1093→  const flows: FlowData[] = [];
  1094→
  1095→  // Walk content/flows/YYYY/MM/ structure
  1096→  const yearDirs = fs.readdirSync(flowsDirectory, { withFileTypes: true });
  1097→  for (const yearEntry of yearDirs) {
  1098→    if (!yearEntry.isDirectory() || !/^\d{4}$/.test(yearEntry.name)) continue;
  1099→    const yearPath = path.join(flowsDirectory, yearEntry.name);
  1100→
  1101→    const monthDirs = fs.readdirSync(yearPath, { withFileTypes: true });
  1102→    for (const monthEntry of monthDirs) {
  1103→      if (!monthEntry.isDirectory() || !/^\d{2}$/.test(monthEntry.name)) continue;
  1104→      const monthPath = path.join(yearPath, monthEntry.name);
  1105→
  1106→      const dayItems = fs.readdirSync(monthPath, { withFileTypes: true });
  1107→      for (const dayItem of dayItems) {
  1108→        const rawName = dayItem.name.replace(/\.mdx?$/, '');
  1109→        if (!/^\d{2}$/.test(rawName)) continue;
  1110→
  1111→        const year = yearEntry.name;
  1112→        const month = monthEntry.name;
  1113→        const day = rawName;
  1114→        const slug = `${year}/${month}/${day}`;
  1115→        let fullPath = '';
  1116→
  1117→        if (dayItem.isFile() && (dayItem.name.endsWith('.md') || dayItem.name.endsWith('.mdx'))) {
  1118→          fullPath = path.join(monthPath, dayItem.name);
  1119→        } else if (dayItem.isDirectory()) {
  1120→          const indexMdx = path.join(monthPath, dayItem.name, 'index.mdx');
  1121→          const indexMd = path.join(monthPath, dayItem.name, 'index.md');
  1122→          if (fs.existsSync(indexMdx)) fullPath = indexMdx;
  1123→          else if (fs.existsSync(indexMd)) fullPath = indexMd;
  1124→          else continue;
  1125→        } else {
  1126→          continue;
  1127→        }
  1128→
  1129→        flows.push(parseFlowFile(fullPath, slug));
  1130→      }
  1131→    }
  1132→  }
  1133→
  1134→  return flows
  1135→    .filter(flow => {
  1136→      if (process.env.NODE_ENV === 'production' && flow.draft) return false;
  1137→      if (!siteConfig.posts?.showFuturePosts) {
  1138→        const flowDate = new Date(flow.date);
  1139→        const now = new Date();
  1140→        if (flowDate > now) return false;
  1141→      }
  1142→      return true;
  1143→    })
  1144→    .sort((a, b) => (a.date < b.date ? 1 : -1));
  1145→}
