  1147→export function getFlowBySlug(slug: string): FlowData | null {
  1148→  if (!fs.existsSync(flowsDirectory)) return null;
  1149→
  1150→  // slug format: "YYYY/MM/DD"
  1151→  const parts = slug.split('/');
  1152→  if (parts.length !== 3) return null;
  1153→  const [year, month, day] = parts;
  1154→
  1155→  const basePath = path.join(flowsDirectory, year, month);
  1156→  if (!fs.existsSync(basePath)) return null;
  1157→
  1158→  // Try flat file
  1159→  const mdxPath = path.join(basePath, `${day}.mdx`);
  1160→  const mdPath = path.join(basePath, `${day}.md`);
  1161→  if (fs.existsSync(mdxPath)) return parseFlowFile(mdxPath, slug);
  1162→  if (fs.existsSync(mdPath)) return parseFlowFile(mdPath, slug);
  1163→
  1164→  // Try folder
  1165→  const indexMdx = path.join(basePath, day, 'index.mdx');
  1166→  const indexMd = path.join(basePath, day, 'index.md');
  1167→  if (fs.existsSync(indexMdx)) return parseFlowFile(indexMdx, slug);
  1168→  if (fs.existsSync(indexMd)) return parseFlowFile(indexMd, slug);
  1169→
  1170→  return null;
  1171→}
