    13→// Use month number as key for reliable sorting across all locales
    14→type GroupedPosts = Record<string, Record<string, PostData[]>>;
    15→
    16→const locale = siteConfig.i18n.defaultLocale === 'zh' ? 'zh-CN' : siteConfig.i18n.defaultLocale;
    17→
    18→function getMonthName(monthNum: number): string {
