    20→}
    21→
    22→function groupPostsByDate(posts: PostData[]): GroupedPosts {
    23→  const groups: GroupedPosts = {};
    24→
    25→  posts.forEach((post) => {
    26→    const date = new Date(post.date);
    27→    const year = date.getFullYear().toString();
    28→    const month = (date.getMonth() + 1).toString();
    29→
    30→    if (!groups[year]) {
    31→      groups[year] = {};
    32→    }
    33→    if (!groups[year][month]) {
    34→      groups[year][month] = [];
    35→    }
    36→    groups[year][month].push(post);
    37→  });
    38→
    39→  return groups;
    40→}
