    98→                {/* Year Marker */}
    99→                <div className="relative">
   100→                  <div className="sticky top-24 lg:top-32 text-left md:text-right">
   101→                    <h2 className="text-4xl md:text-5xl font-serif font-bold text-muted/50">
   102→                      {year}
   103→                    </h2>
   104→                    <span className="block text-xs font-bold uppercase tracking-widest text-muted mt-2">
   105→                      {yearTotal} {t('posts')}
   106→                    </span>
   107→                  </div>
   108→                </div>
   109→                
   110→                {/* Content Timeline */}
   111→                <div className="relative border-l-2 border-muted/20 pl-8 md:pl-12 space-y-16">
   112→                  {months.map((month) => {
