     5→import { t, tWith } from '@/lib/i18n';
     6→import { LuTag, LuX, LuSearch } from 'react-icons/lu';
     7→
     8→const INITIAL_SHOW = 12;
     9→
    10→interface TagSidebarProps {
    11→  tags: Record<string, number>;
    12→  activeTag: string;
    13→}
    14→
    15→export default function TagSidebar({ tags, activeTag }: TagSidebarProps) {
    16→  const [filter, setFilter] = useState('');
    17→  const [expanded, setExpanded] = useState(false);
    18→
    19→  const totalCount = Object.keys(tags).length;
    20→
    21→  const sortedTags = Object.entries(tags)
    22→    .sort((a, b) => b[1] - a[1])
    23→    .filter(([tag]) => !filter || tag.toLowerCase().includes(filter.toLowerCase()));
    24→
    25→  const activeIndex = sortedTags.findIndex(([tag]) => tag === activeTag);
    26→
    27→  // Compute visible tags:
    28→  // - Filtering or expanded: show all
    29→  // - Default: show first INITIAL_SHOW, then append active tag (with a separator)
    30→  //   if it falls beyond the initial slice — keeps sidebar compact while
    31→  //   always making the selected tag visible
    32→  const getVisibleTags = (): { entries: [string, number][]; appendedAt: number | null } => {
    33→    if (filter || expanded) return { entries: sortedTags, appendedAt: null };
    34→    const initial = sortedTags.slice(0, INITIAL_SHOW);
    35→    if (activeIndex >= INITIAL_SHOW) {
    36→      return { entries: [...initial, sortedTags[activeIndex]], appendedAt: INITIAL_SHOW };
    37→    }
    38→    return { entries: initial, appendedAt: null };
    39→  };
    40→
    41→  const { entries: visibleTags, appendedAt } = getVisibleTags();
    42→  const remainingCount = sortedTags.length - visibleTags.length;
    43→  const showExpandButton = !filter && !expanded && remainingCount > 0;
    44→  // Only allow collapsing if it won't hide the active tag
    45→  const showCollapseButton = expanded && !filter && (activeIndex === -1 || activeIndex < INITIAL_SHOW);
    46→
    47→  return (
    48→    <aside className="hidden lg:block flex-shrink-0">
    49→      <div className="sticky top-24">
    50→
    51→        {/* Section heading → links to all tags, shows total count */}
    52→        <Link
    53→          href="/tags"
    54→          className="flex items-center gap-1.5 text-[10px] font-sans font-bold uppercase tracking-widest text-muted hover:text-accent transition-colors no-underline mb-3"
    55→        >
    56→          <LuTag className="w-3 h-3" />
    57→          <span>{t('tags')}</span>
    58→          <span className="ml-auto font-mono font-normal normal-case tracking-normal text-muted/50">
    59→            {totalCount}
    60→          </span>
    61→        </Link>
    62→
    63→        {/* Filter input with clear button */}
    64→        <div className="relative mb-3">
    65→          <LuSearch className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3 h-3 text-muted/40 pointer-events-none" />
    66→          <input
    67→            type="text"
    68→            value={filter}
    69→            onChange={(e) => setFilter(e.target.value)}
    70→            placeholder="Filter…"
    71→            aria-label={t('filter_tags')}
    72→            className="w-full pl-8 pr-7 py-1.5 text-xs bg-muted/5 border border-muted/15 rounded-lg outline-none focus:border-accent/40 text-foreground placeholder:text-muted/40 transition-colors"
    73→          />
    74→          {filter && (
    75→            <button
    76→              onClick={() => setFilter('')}
    77→              className="absolute right-2 top-1/2 -translate-y-1/2 text-muted/40 hover:text-muted transition-colors p-0.5 rounded"
    78→              aria-label="Clear filter"
    79→            >
    80→              <LuX className="w-3 h-3" />
    81→            </button>
    82→          )}
    83→        </div>
    84→
    85→        {/* Tag list — no overflow, no scrollbar */}
    86→        <nav className="space-y-0.5">
    87→          {visibleTags.map(([tag, count], index) => {
    88→            const isActive = tag === activeTag;
    89→            // Thin separator before the appended active tag
    90→            const showSeparator = appendedAt !== null && index === appendedAt;
    91→            return (
    92→              <div key={tag}>
    93→                {showSeparator && <div className="my-1.5 h-px bg-muted/10" />}
    94→                <Link
    95→                  href={`/tags/${encodeURIComponent(tag)}`}
    96→                  className={`flex items-center justify-between px-2.5 py-1.5 rounded-lg text-sm no-underline transition-colors ${
    97→                    isActive
    98→                      ? 'bg-accent/10 text-accent font-medium'
    99→                      : 'text-foreground/70 hover:text-foreground hover:bg-muted/10'
   100→                  }`}
   101→                >
   102→                  <span className="truncate">{tag}</span>
   103→                  <span className={`ml-2 text-xs font-mono flex-shrink-0 ${isActive ? 'text-accent/70' : 'text-muted/50'}`}>
   104→                    {count}
   105→                  </span>
   106→                </Link>
   107→              </div>
   108→            );
   109→          })}
   110→
   111→          {/* Expand button */}
   112→          {showExpandButton && (
   113→            <button
   114→              onClick={() => setExpanded(true)}
   115→              aria-expanded={false}
   116→              className="w-full text-left px-2.5 py-1.5 text-xs text-muted/50 hover:text-accent transition-colors"
   117→            >
   118→              {tWith('more_tags', { count: remainingCount })}
   119→            </button>
   120→          )}
   121→
   122→          {/* Collapse button */}
   123→          {showCollapseButton && (
   124→            <button
