    ? tWith(effectiveKey, subtitleParams)
    : t(effectiveKey);

  return (
    <header className={`page-header ${className || ''}`}>
      <h1 className="page-title">{title}</h1>
      <p className="page-subtitle">{subtitle}</p>
    </header>
